from collections import defaultdict
from bisect import bisect_right

def solve(nums: list[int], queries: list[list[int]]) -> list[int]:
    n = len(nums)
    ans = []

    # Preprocess the array to create a list of prefix counts for each number
    prefix_counts = [defaultdict(int) for _ in range(n + 1)]
    for i in range(n):
        for num in prefix_counts[i]:
            prefix_counts[i + 1][num] = prefix_counts[i][num]
        prefix_counts[i + 1][nums[i]] += 1

    for l, r, threshold in queries:
        freq = defaultdict(int)
        for i in range(l, r + 1):
            freq[nums[i]] += 1

        max_freq = -1
        result = -1
        for num, count in freq.items():
            if count >= threshold:
                if count > max_freq or (count == max_freq and num < result):
                    max_freq = count
                    result = num
        ans.append(result)

    return ans
